// ==============================================================================
// 2. HARDWARE REGISTER MAP
// ==============================================================================
#define CIM_BASE CIMMETRY_1616_0_BASE
#define REG_CTRL     0
#define REG_BASE_A   1
#define REG_BASE_B   2
#define REG_BASE_C   3
#define REG_STRIDE_A 4
#define REG_STRIDE_B 5
#define REG_STRIDE_C 6
#define SPAD_OFFSET  0x1000

#define CIM_WRITE_REG(offset, data) IOWR(CIM_BASE, offset, data)
#define CIM_READ_REG(offset)        IORD(CIM_BASE, offset)
#define CIM_WRITE_SPAD(addr, data)  IOWR(CIM_BASE, SPAD_OFFSET + (addr), data)
#define CIM_READ_SPAD(addr)         (int8_t)IORD(CIM_BASE, SPAD_OFFSET + (addr))

#define PRISM_BASE PRISM_16_0_BASE
#define PRISM_OFFSET_X    0
#define PRISM_OFFSET_Y    16
#define PRISM_OFFSET_CTRL 32
#define PRISM_OFFSET_Z    48
#define PRISM_CMD_RELU    0x01

#define CLASSIFICATION_THRESHOLD_SQ 11837

// ==============================================================================
// 3. HARDWARE ABSTRACTION LAYER (HAL)
// ==============================================================================

// TILED MAC ENGINE: Overcomes the 128-byte scratchpad limit by slicing W into 16x4 blocks.
void hal_cimmetry_mac_tiled(tensor4x16_t* A, const tensor16x16_t* W_full, tensor4x16_t* C_out, int out_cols) {
    int num_blocks = out_cols / 4;

    CIM_WRITE_REG(REG_STRIDE_A, 16);
    CIM_WRITE_REG(REG_STRIDE_B, 16);
    CIM_WRITE_REG(REG_STRIDE_C, 4);

    for (int b = 0; b < num_blocks; b++) {
        // 1. Load A (4x16 = 64 bytes) to SPAD[0..63]. Must reload every loop because C overwrites it.
        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 16; j++) {
                CIM_WRITE_SPAD(0 + (i * 16) + j, A->mat[i][j]);
            }
        }

        // 2. Load W block (16x4 = 64 bytes) to SPAD[64..127]. Column-major orientation for Systolic array.
        for (int col = 0; col < 4; col++) {
            for (int row = 0; row < 16; row++) {
                int w_col = (b * 4) + col;
                CIM_WRITE_SPAD(64 + (col * 16) + row, W_full->mat[row][w_col]);
            }
        }

        // 3. Configure Bases & Fire
        CIM_WRITE_REG(REG_BASE_A, 0);
        CIM_WRITE_REG(REG_BASE_B, 64);
        CIM_WRITE_REG(REG_BASE_C, 0); // Safely overwrite A to fit within 128 bytes

        CIM_WRITE_REG(REG_CTRL, 0x01);
        while ((CIM_READ_REG(REG_CTRL) & 0x02) == 0);

        // 4. Extract C block (4x4) from SPAD[0..15] and append to C_out matrix
        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 4; j++) {
                int out_col = (b * 4) + j;
                C_out->mat[i][out_col] = CIM_READ_SPAD(0 + (i * 4) + j);
            }
        }
    }
}

// Restored PRISM hardware call.
void hal_prism_relu(tensor4x16_t* target) {
    uint32_t* word_ptr = (uint32_t*)target;
    for (int row = 0; row < 4; row++) {
        // Little-endian packed 32-bit writes
        for (int i = 0; i < 4; i++)
            IOWR_32DIRECT(PRISM_BASE, PRISM_OFFSET_X + (i * 4), word_ptr[(row * 4) + i]);

        IOWR_32DIRECT(PRISM_BASE, PRISM_OFFSET_CTRL, PRISM_CMD_RELU);
        while ((IORD_32DIRECT(PRISM_BASE, PRISM_OFFSET_CTRL) & 0x02) == 0);

        for (int i = 0; i < 4; i++)
            word_ptr[(row * 4) + i] = IORD_32DIRECT(PRISM_BASE, PRISM_OFFSET_Z + (i * 4));
    }
}

// ==============================================================================
// 4. NEURAL NETWORK API
// ==============================================================================
void nn_spatial_convolution(const tensor32x32_t* img, const tensor16x16_t* W, tensor4x16_t out_maps[16]) {
    int t_idx = 0;
    int row_idx = 0;
    tensor4x16_t temp_a;

    for (int r = 0; r < 32; r += 4) {
        for (int c = 0; c < 32; c += 4) {

            int p = 0;
            for (int i = 0; i < 4; i++) {
                for (int j = 0; j < 4; j++) {
                    temp_a.mat[row_idx][p++] = img->mat[r + i][c + j];
                }
            }
            row_idx++;

            if (row_idx == 4) {
                // Tiled MAC processing 16 output channels
                hal_cimmetry_mac_tiled(&temp_a, W, &out_maps[t_idx], 16);
                hal_prism_relu(&out_maps[t_idx]);
                t_idx++;
                row_idx = 0;
            }
        }
    }
}

void nn_quadrant_pooling(const tensor4x16_t in_maps[16], tensor4x16_t* pooled_out) {
    for (int q = 0; q < 4; q++) {
        int r_start = (q / 2) * 4;
        int c_start = (q % 2) * 4;

        for (int ch = 0; ch < 16; ch++) {
            int32_t sum = 0;
            for (int r = 0; r < 4; r++) {
                for (int c = 0; c < 4; c++) {
                    int patch_idx = (r_start + r) * 8 + (c_start + c);
                    int t_idx = patch_idx / 4;
                    int row_idx = patch_idx % 4;
                    sum += in_maps[t_idx].mat[row_idx][ch];
                }
            }
            pooled_out->mat[q][ch] = (int8_t)(sum / 16);
        }
    }
}

void nn_dense_projection(tensor4x16_t* pooled_in, const tensor16x16_t* W_proj, tensor1x32_t* final_sig) {
    tensor4x16_t dense_out;
    // W_linear only has 8 active columns, so we process 8 output channels
    hal_cimmetry_mac_tiled(pooled_in, W_proj, &dense_out, 8);

    // Extract the active 8x4 matrix into the flattened 32-byte array
    for(int r = 0; r < 4; r++) {
        for(int c = 0; c < 8; c++) {
            final_sig->vec[r * 8 + c] = dense_out.mat[r][c];
        }
    }
}

int32_t calculate_sq_distance(const int8_t* live_sig, const int8_t* anchor) {
    int32_t dist = 0;
    for (int i = 0; i < 32; i++) {
        int32_t diff = live_sig[i] - anchor[i];
        dist += (diff * diff);
    }
    return dist;
}

