void ui_print_distance_bar(int person_id, int32_t dist) {
    int max_val = 20000;
    int width = 30;
    int filled = (dist > max_val) ? width : (dist * width / max_val);
    int thresh_mark = (CLASSIFICATION_THRESHOLD_SQ * width / max_val);

    printf(" Anchor %d | Dist: %5d | [", person_id, dist);
    for(int i = 0; i < width; i++) {
        if (i == thresh_mark) printf("|");
        else if (i < filled) printf("=");
        else printf(" ");
    }
    printf("] ");

    if (dist < CLASSIFICATION_THRESHOLD_SQ) printf("--> MATCH\n");
    else printf("\n");
}

