int main() {
    ui_print_banner();

    const int8_t (*test_suite[6])[32] = {
        Person_0_Test_0, Person_0_Test_1,
        Person_1_Test_0, Person_1_Test_1,
        Person_2_Test_0, Person_2_Test_1
    };

    const char* test_names[6] = {
        "Person_0_Test_0", "Person_0_Test_1",
        "Person_1_Test_0", "Person_1_Test_1",
        "Person_2_Test_0", "Person_2_Test_1"
    };

    tensor4x16_t cycle1_maps[16];
    tensor4x16_t pooled_map;
    tensor1x32_t face_signature;

    for (int t = 0; t < 6; t++) {
        printf("\n[*] --------------------------------------------------------\n");
        printf("[*] ACQUIRING LIVE STREAM: %s\n", test_names[t]);
        printf("[*] --------------------------------------------------------\n");

        const tensor32x32_t* live_feed = (const tensor32x32_t*)test_suite[t];

        nn_spatial_convolution(live_feed, &W_conv, cycle1_maps);
        nn_quadrant_pooling(cycle1_maps, &pooled_map);
        nn_dense_projection(&pooled_map, &W_linear, &face_signature);

        int32_t dist_0 = calculate_sq_distance(face_signature.vec, Anchor_Person_0);
        int32_t dist_1 = calculate_sq_distance(face_signature.vec, Anchor_Person_1);
        int32_t dist_2 = calculate_sq_distance(face_signature.vec, Anchor_Person_2);

        ui_print_distance_bar(0, dist_0);
        ui_print_distance_bar(1, dist_1);
        ui_print_distance_bar(2, dist_2);

        int32_t lowest_dist = dist_0;
        int best_match = 0;
        if(dist_1 < lowest_dist) { lowest_dist = dist_1; best_match = 1; }
        if(dist_2 < lowest_dist) { lowest_dist = dist_2; best_match = 2; }

        printf(" -----------------------------------------------------------\n");
        if(lowest_dist < CLASSIFICATION_THRESHOLD_SQ) {
            printf(" >>> ACCESS GRANTED: Welcome, Authorized User %d <<<\n", best_match);
        } else {
            printf(" >>> ACCESS DENIED: Identity Not Recognized <<<\n");
        }
    }

    printf("\n========================================================================\n");
    printf("  ALL DIAGNOSTICS COMPLETE. SYSTEM STANDBY.\n");
    printf("========================================================================\n\n");

    return 0;
}
